-- MariaDB supports IF [NOT] EXISTS conditional clauses on the index and
-- constraint actions of ALTER TABLE. MySQL does not.
-- https://mariadb.com/docs/server/reference/sql-statements/data-definition/alter/alter-table

-- The original repro: DROP INDEX IF EXISTS then ADD INDEX in one statement.
ALTER TABLE `t` DROP INDEX IF EXISTS `idx_old`, ADD INDEX `idx_new` (`a`, `b`);

-- ADD {INDEX|KEY} [IF NOT EXISTS]
ALTER TABLE `t` ADD INDEX IF NOT EXISTS `idx_new` (`a`, `b`);
ALTER TABLE `t` ADD KEY IF NOT EXISTS `idx_new` (`a`, `b`);
ALTER TABLE `t` ADD INDEX IF NOT EXISTS (`a`, `b`);

-- DROP {INDEX|KEY} [IF EXISTS]
ALTER TABLE `t` DROP INDEX IF EXISTS `idx_old`;
ALTER TABLE `t` DROP KEY IF EXISTS `idx_old`;

-- ADD [COLUMN] [IF NOT EXISTS] / DROP [COLUMN] [IF EXISTS]
ALTER TABLE `t` ADD COLUMN IF NOT EXISTS `c` INT;
ALTER TABLE `t` ADD IF NOT EXISTS `c` INT;
ALTER TABLE `t` DROP COLUMN IF EXISTS `c`;
ALTER TABLE `t` DROP IF EXISTS `c`;

-- CHANGE / MODIFY [COLUMN] [IF EXISTS]
ALTER TABLE `t` CHANGE COLUMN IF EXISTS `c` `d` INT;
ALTER TABLE `t` CHANGE IF EXISTS `c` `d` INT;
ALTER TABLE `t` MODIFY COLUMN IF EXISTS `c` BIGINT;
ALTER TABLE `t` MODIFY IF EXISTS `c` BIGINT;

-- ADD [CONSTRAINT [symbol]] PRIMARY KEY [IF NOT EXISTS]
ALTER TABLE `t` ADD PRIMARY KEY IF NOT EXISTS (`a`);
ALTER TABLE `t` ADD CONSTRAINT `pk` PRIMARY KEY IF NOT EXISTS (`a`);

-- ADD [CONSTRAINT [symbol]] UNIQUE [INDEX|KEY] [IF NOT EXISTS]
ALTER TABLE `t` ADD UNIQUE IF NOT EXISTS `uq` (`a`);
ALTER TABLE `t` ADD UNIQUE INDEX IF NOT EXISTS `uq` (`a`);
ALTER TABLE `t` ADD CONSTRAINT `uq` UNIQUE KEY IF NOT EXISTS (`a`);

-- ADD [CONSTRAINT [symbol]] FOREIGN KEY [IF NOT EXISTS]
ALTER TABLE `t` ADD FOREIGN KEY IF NOT EXISTS `fk` (`a`) REFERENCES `y` (`b`);
ALTER TABLE `t`
ADD CONSTRAINT `fk` FOREIGN KEY IF NOT EXISTS (`a`) REFERENCES `y` (`b`);

-- ADD {FULLTEXT|SPATIAL} [INDEX|KEY] [IF NOT EXISTS]
ALTER TABLE `t` ADD FULLTEXT INDEX IF NOT EXISTS `ft` (`a`);
ALTER TABLE `t` ADD SPATIAL KEY IF NOT EXISTS `sp` (`a`);

-- DROP FOREIGN KEY [IF EXISTS] / DROP CONSTRAINT [IF EXISTS]
ALTER TABLE `t` DROP FOREIGN KEY IF EXISTS `fk`;
ALTER TABLE `t` DROP CONSTRAINT IF EXISTS `chk`;

-- ALTER {INDEX|KEY} [IF EXISTS] index_name [NOT] IGNORED
ALTER TABLE `t` ALTER INDEX IF EXISTS `idx` IGNORED;
ALTER TABLE `t` ALTER KEY IF EXISTS `idx` NOT IGNORED;
